INSERT INTO `book_page` (`id`, `book_id`, `page_no`, `title`, `content_type`, `content_text_ko`, `content_text_en`, `image_url`, `created_at`, `updated_at`) VALUES
(1, 1, 1, '따뜻한 저녁', 'POEM', '비가 그치자 무지개가 마을을 감쌌습니다. 숲속에서 들려오는 소리에 귀를 기울였습니다. 겨울이 지나고 봄이 오자 나무에 새싹이 돋았습니다. 오랜 기다림 끝에 반가운 소식이 도착했습니다.', 'Excepturi saepe qui illo blanditiis placeat. Consequatur saepe recusandae quisquam nihil excepturi blanditiis. Quidem cumque fuga cumque. Unde aliquam aut sed nostrum.', NULL, '2026-05-12 19:48:13', '2026-05-15 19:48:13'),
(2, 1, 2, '비 오는 날', 'POEM', '구름 사이로 햇살이 비치자 모두가 미소지었습니다. 비가 그치자 무지개가 마을을 감쌌습니다. 아이는 손을 흔들며 친구에게 인사했습니다. 오랜 기다림 끝에 반가운 소식이 도착했습니다.', 'Nostrum at repudiandae error in nam deleniti. Voluptate nulla sint voluptates magni iure occaecati. Eius deserunt recusandae placeat voluptas. Libero cum ullam amet facilis distinctio dolorum.', 'https://cdn.sangsangseoga.com/page/2.png', '2026-04-11 09:35:42', '2026-04-16 09:35:42'),
(3, 1, 3, '새로운 친구', 'POEM', '바람이 불 때마다 나뭇잎이 춤을 추듯 흔들렸습니다.', 'Ratione odit nostrum cumque. Sequi assumenda sequi laudantium voluptatum nihil saepe. Accusamus incidunt sit dolorum ipsa. Tempora nihil corrupti nemo a. Aliquam iusto quisquam. Incidunt hic repellat.', 'https://cdn.sangsangseoga.com/page/3.png', '2025-07-21 10:59:21', '2025-08-04 10:59:21'),
(4, 1, 4, '작은 결심', 'POEM', '겨울이 지나고 봄이 오자 나무에 새싹이 돋았습니다. 처음엔 무서웠지만 곧 용기를 내기로 했습니다. 비가 그치자 무지개가 마을을 감쌌습니다. 함께라면 무엇이든 해낼 수 있을 것 같았습니다.', 'Beatae facilis nulla. Facilis officia provident natus quo consequuntur. Dolores beatae laboriosam vel neque vero. Quidem quis eum tempore magnam. Eius aperiam exercitationem laborum minima commodi.', NULL, '2026-03-05 13:54:04', '2026-03-21 13:54:04'),
(5, 1, 5, '함께한 하루', 'POEM', '아이는 손을 흔들며 친구에게 인사했습니다.', 'Nihil possimus sapiente ipsum esse consequatur ratione. Ratione dolorem fuga enim. Corporis eligendi vero. Unde quae eligendi voluptate saepe possimus pariatur corrupti. Blanditiis voluptatibus nemo ipsam fuga.', 'https://cdn.sangsangseoga.com/page/5.png', '2025-10-19 19:32:04', '2025-11-07 19:32:04'),
(6, 1, 6, '함께한 하루', 'POEM', '비가 그치자 무지개가 마을을 감쌌습니다. 모두가 잠든 밤, 별들이 조용히 이야기를 나누었습니다. 새로운 친구를 만난 순간, 마음이 두근거렸습니다. 바람이 불 때마다 나뭇잎이 춤을 추듯 흔들렸습니다. 달빛 아래에서 두 친구는 오래도록 이야기를 나누었습니다.', 'Illo sapiente ipsum. Eveniet non deserunt minima. Deserunt assumenda sed perspiciatis vero. Hic laudantium nobis maiores animi pariatur id.', 'https://cdn.sangsangseoga.com/page/6.png', '2025-12-20 06:48:33', '2026-01-07 06:48:33'),
(7, 1, 7, '첫 만남', 'POEM', '구름 사이로 햇살이 비치자 모두가 미소지었습니다. 바람이 불 때마다 나뭇잎이 춤을 추듯 흔들렸습니다. 겨울이 지나고 봄이 오자 나무에 새싹이 돋았습니다. 새로운 친구를 만난 순간, 마음이 두근거렸습니다.', 'Laudantium reprehenderit error nesciunt laudantium qui dolore. Culpa error odit. Commodi pariatur enim debitis tenetur officia adipisci. Laudantium voluptas nisi facere laboriosam.', 'https://cdn.sangsangseoga.com/page/7.png', '2025-11-18 18:43:59', '2025-12-15 18:43:59'),
(8, 1, 8, '비 오는 날', 'POEM', '작은 실수도 함께 웃으며 넘길 수 있었습니다. 구름 사이로 햇살이 비치자 모두가 미소지었습니다. 작은 마을에 사는 아이는 매일 창밖을 바라보았습니다.', 'Quibusdam molestiae sit repudiandae placeat error placeat porro. Modi expedita corporis consequatur. Fuga laborum excepturi tenetur aut.', 'https://cdn.sangsangseoga.com/page/8.png', '2025-07-02 09:24:16', '2025-07-28 09:24:16'),
(9, 2, 1, '마지막 인사', 'CHAPTER', '함께라면 무엇이든 해낼 수 있을 것 같았습니다. 처음엔 무서웠지만 곧 용기를 내기로 했습니다. 오랜 기다림 끝에 반가운 소식이 도착했습니다. 달빛 아래에서 두 친구는 오래도록 이야기를 나누었습니다.', 'Recusandae maiores animi. Tenetur aliquam error ab. Quos ullam dignissimos temporibus.', 'https://cdn.sangsangseoga.com/page/9.png', '2025-10-07 10:01:55', '2025-11-05 10:01:55'),
(10, 2, 2, '새로운 친구', 'CHAPTER', '비가 그치자 무지개가 마을을 감쌌습니다.', 'Sed labore praesentium delectus perferendis autem rerum. Incidunt maiores illum quis et iure. Consequatur quis provident nam aliquam eveniet blanditiis. Itaque quasi porro sapiente dolorem.', 'https://cdn.sangsangseoga.com/page/10.png', '2025-04-25 05:08:59', '2025-05-16 05:08:59'),
(11, 2, 3, '첫 만남', 'CHAPTER', '함께라면 무엇이든 해낼 수 있을 것 같았습니다. 처음엔 무서웠지만 곧 용기를 내기로 했습니다.', 'Doloremque incidunt libero quisquam. Nisi quidem reiciendis velit explicabo pariatur veniam voluptates. Eius quisquam autem dolorum libero occaecati consequatur. Qui rerum libero ad. Fugit perspiciatis corrupti numquam.', 'https://cdn.sangsangseoga.com/page/11.png', '2025-05-20 22:21:32', '2025-05-27 22:21:32'),
(12, 2, 4, '약속의 순간', 'CHAPTER', '구름 사이로 햇살이 비치자 모두가 미소지었습니다. 새로운 친구를 만난 순간, 마음이 두근거렸습니다.', 'Quisquam numquam fugit. Exercitationem facere expedita optio dolorum officia. Assumenda porro sit beatae cumque modi alias omnis. Necessitatibus temporibus eaque possimus nihil voluptates. Necessitatibus eum atque laborum porro dignissimos. Magnam quisquam excepturi nostrum facilis ipsa libero.', 'https://cdn.sangsangseoga.com/page/12.png', '2025-07-10 13:27:20', '2025-07-21 13:27:20'),
(13, 2, 5, '약속의 순간', 'CHAPTER', '모두가 잠든 밤, 별들이 조용히 이야기를 나누었습니다. 구름 사이로 햇살이 비치자 모두가 미소지었습니다. 달빛 아래에서 두 친구는 오래도록 이야기를 나누었습니다. 비가 그치자 무지개가 마을을 감쌌습니다. 함께라면 무엇이든 해낼 수 있을 것 같았습니다. 겨울이 지나고 봄이 오자 나무에 새싹이 돋았습니다.', 'Sunt occaecati maiores delectus. Distinctio vitae quia iusto vel minus nostrum. Vel quas animi dicta iure dolores. Sapiente illum similique tenetur odio. Eaque enim cum porro doloremque dolores. Deleniti doloribus repudiandae iure.', 'https://cdn.sangsangseoga.com/page/13.png', '2026-03-22 03:43:27', '2026-04-03 03:43:27'),
